  ?series wdt:P31 wd:Q2181514 ;
          rdfs:label "Hanna" (lang:en) ;
          wdt:P577 ?airDate .
  FILTER (STRSTARTS(STR(?airDate), "2019-")) .
  ?series wdt:P57 ?director
}

